#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
LL K,m;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL QP(LL x,LL y,LL mod){
    LL as=1;
    while(y){
        if(y&1)as=(_i128)(as)*x%mod;
        x=(_i128)(x)*x%mod,y>>=1;
    }return as;
}
LL BSGS(LL x,LL y,LL mod){
    unordered_map<LL,LL> mp;
    mp.clear();
    x%=mod,y%=mod;
    LL m=sqrt(mod)+2,tmp=y;
    for(int i=1;i<=m;i++)
        tmp=((_i128)(tmp)*x)%mod,mp[tmp]=i;
    LL fan=QP(x,m,mod);tmp=1;
    for(int i=1;i<=m;i++){
        tmp=((_i128)(tmp)*fan)%mod;
        if(mp[tmp]>0)return i*m-mp[tmp];
    }return -1;
}
int main(){
    K=read(),m=read();
    K=(K*9+1)%m;
    cout<<BSGS(10,K,m)<<"\n";
    return 0;
}
